export const MOCK_TAX_PAYMENTS: TaxPayment[] = [];
export const MOCK_INPUT_INVOICES: InputInvoice[] = [];
export const MOCK_TAX_TICKETS: TaxTicket[] = [];
export const MOCK_INVOICES: Invoice[] = [];
